```html
<!doctype html>
<html>
  <head>
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <link rel="preconnect" href="[https://fonts.googleapis.com](https://fonts.googleapis.com)" />
    <link rel="preconnect" href="[https://fonts.gstatic.com](https://fonts.gstatic.com)" crossorigin />
    <link
      href="[https://fonts.googleapis.com/css2?family=Cinzel:wght@500;700;900&family=Noto+Serif+SC:wght@400;700&display=swap](https://fonts.googleapis.com/css2?family=Cinzel:wght@500;700;900&family=Noto+Serif+SC:wght@400;700&display=swap)"
      rel="stylesheet"
    />
    <style>
      :root {
        --void-deep: #02040a;
        --text-color: #e6f1ff;
        --gate-border: #4a148c;
        --gate-glow: #00e5ff;

        /* 核心配色：银色神性 */
        --silver-primary: #e0f7fa;
        --silver-glow: rgba(200, 240, 255, 0.8);
        --witch-purple: #7b1fa2;
        --witch-cyan: #00e5ff;
        --toxic-chartreuse: #8fff00;

        --q-common: #b0c4de;
        --q-excellent: #00e676;
        --q-rare: #00bcd4;
        --q-epic: #9c27b0;
        --q-legend: #ffd700;
        --q-mythic: #ff5252;
        --q-other: #78909c;

        --blur-strength: 42px;
        --star-scale: 0.82;
        --fx-opacity: 1;
      }

      @media (max-width: 768px) {
        :root {
          --blur-strength: 28px;
          --star-scale: 0.64;
          --fx-opacity: 0.72;
        }
      }
      @media (min-width: 1920px) {
        :root {
          --blur-strength: 72px;
          --star-scale: 1.1;
          --fx-opacity: 0.9;
        }
      }

      html,
      body {
        margin: 0;
        padding: 0;
        background: transparent;
        min-height: 100vh;
        overflow-x: hidden;
        overflow-y: auto;
      }

      /* 极限性能保护：在低性能/高数据量时自动降级但保留风格骨架 */
      .gate-root.perf-lite .noise-overlay,
      .gate-root.perf-lite .arm-secondary,
      .gate-root.perf-lite .blob-blue,
      .gate-root.perf-lite .stars-2,
      .gate-root.perf-lite .gate-light-burst {
        display: none !important;
      }

      .gate-root.perf-lite .mc-outer,
      .gate-root.perf-lite .mc-mid,
      .gate-root.perf-lite .mc-inner,
      .gate-root.perf-lite .sym-ring,
      .gate-root.perf-lite .sym-floater,
      .gate-root.perf-lite .sym-dust,
      .gate-root.perf-lite .arm-primary,
      .gate-root.perf-lite .blob-purple,
      .gate-root.perf-lite .blob-green,
      .gate-root.perf-lite .stars-1,
      .gate-root.perf-lite .key-halo,
      .gate-root.perf-lite .key-halo::after,
      .gate-root.perf-lite .orb-epic,
      .gate-root.perf-lite .orb-legend,
      .gate-root.perf-lite .orb-mythic {
        animation: none !important;
      }

      .gate-root.perf-lite .galaxy-arm {
        filter: blur(14px);
        opacity: 0.12;
      }

      .gate-root.perf-lite .chaos-blob {
        filter: blur(16px);
        opacity: 0.12;
      }

      .gate-root.perf-lite .gate-door,
      .gate-root.perf-lite .modal-backdrop,
      .gate-root.perf-lite .skill-orb {
        backdrop-filter: none !important;
      }

      .gate-root.perf-lite .skill-orb {
        transition:
          transform 0.2s ease,
          box-shadow 0.2s ease,
          border-color 0.2s ease;
      }

      .gate-root.perf-lite .skill-orb:hover {
        transform: translateY(-4px) scale(1.01) !important;
      }

      /* === 核心容器：宽屏 + 高度限制 === */
      .gate-root {
        position: relative;
        width: 100%;
        max-width: none;
        margin: 15px 0;
        min-height: 750px;
        height: auto;

        background: radial-gradient(circle at center, #1b2735 0%, var(--void-deep) 100%);
        border-top: 1px solid rgba(75, 0, 130, 0.5);
        border-bottom: 1px solid rgba(75, 0, 130, 0.5);
        border-left: 1px solid rgba(75, 0, 130, 0.3);
        border-right: 1px solid rgba(75, 0, 130, 0.3);
        border-radius: 8px;

        box-shadow:
          0 0 40px rgba(0, 0, 0, 0.8),
          inset 0 0 100px rgba(0, 0, 0, 0.8);
        overflow: hidden;
        font-family: 'Noto Serif SC', 'Georgia', serif;
        color: var(--text-color);
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: flex-start;
        perspective: 1500px;
        padding-bottom: 50px;
        z-index: 1;
      }

      /* === 背景系统 === */
      .bg-container {
        position: absolute;
        inset: 0;
        overflow: hidden;
        z-index: -1;
        background-color: var(--void-deep);
      }
      .void-base {
        position: absolute;
        inset: 0;
        background: radial-gradient(circle at 50% 50%, #1a1f35 0%, var(--void-deep) 80%);
        z-index: -3;
        opacity: 0.9;
      }
      .noise-overlay {
        position: absolute;
        inset: -30%;
        width: 160%;
        height: 160%;
        background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='[http://www.w3.org/2000/svg'%3E%3Cfilter](http://www.w3.org/2000/svg'%3E%3Cfilter) id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.58' numOctaves='2' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)' opacity='0.12'/%3E%3C/svg%3E");
        opacity: calc(0.03 * var(--fx-opacity));
        mix-blend-mode: overlay;
        animation: noise-shift 10s steps(1) infinite;
        pointer-events: none;
        z-index: -2;
      }

      /* === 银色星阵系统 (Silver Symbol Array) === */
      .symbol-layer {
        position: absolute;
        top: 50%;
        left: 50%;
        width: 100%;
        height: 100%;
        pointer-events: none;
        z-index: -2;
        transform: translate(-50%, -50%);
      }

      /* 通用符号样式：银色辉光 */
      .sym-common {
        position: absolute;
        font-family: 'Times New Roman', serif;
        user-select: none;
        display: flex;
        align-items: center;
        justify-content: center;
        color: var(--silver-primary);
        text-shadow:
          0 0 10px var(--silver-glow),
          0 0 20px rgba(255, 255, 255, 0.4);
      }

      /* 1. 魔法阵线框 (Geometric Rings) */
      .magic-circle-group {
        position: absolute;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
      }
      .mc-ring {
        position: absolute;
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
        border-radius: 50%;
        box-shadow: 0 0 15px rgba(200, 230, 255, 0.1);
      }
      /* 外环：银色实线 */
      .mc-outer {
        width: 75vmin;
        height: 75vmin;
        border: 1px solid rgba(200, 230, 255, 0.3);
        animation: mech-spin 120s linear infinite;
      }
      /* 中环：双虚线，带青色光晕 */
      .mc-mid {
        width: 55vmin;
        height: 55vmin;
        border: 2px dashed rgba(0, 229, 255, 0.2);
        animation: mech-spin 80s linear infinite reverse;
      }
      /* 内环：点阵 */
      .mc-inner {
        width: 38vmin;
        height: 38vmin;
        border: 2px dotted rgba(255, 255, 255, 0.4);
        animation: mech-spin 40s linear infinite;
      }

      /* 2. 符号环 (Symbol Ring) */
      .sym-ring {
        position: absolute;
        top: 50%;
        left: 50%;
        width: 60vmin;
        height: 60vmin;
        transform: translate(-50%, -50%);
        animation: mech-spin 90s linear infinite;
      }
      .sym-ring-item {
        position: absolute;
        font-size: 4vmin; /* 明显的大字体 */
        font-weight: bold;
      }
      .pos-n {
        top: 0;
        left: 50%;
        transform: translate(-50%, -50%);
      }
      .pos-s {
        bottom: 0;
        left: 50%;
        transform: translate(-50%, 50%);
      }
      .pos-e {
        right: 0;
        top: 50%;
        transform: translate(50%, -50%);
      }
      .pos-w {
        left: 0;
        top: 50%;
        transform: translate(-50%, -50%);
      }

      /* 3. 核心符文 (Core Sigils) */
      .sym-floater {
        color: rgba(220, 230, 255, 0.15);
        text-shadow: 0 0 20px rgba(123, 31, 162, 0.2);
        filter: blur(1px);
        animation: symbol-breathe 12s ease-in-out infinite alternate;
      }
      /* 巨大的守望者印记 */
      .sf-main {
        top: 50%;
        left: 50%;
        transform: translate(-50%, -50%);
        font-size: 25vmin; /* 占据中心 */
        animation: mech-spin 200s linear infinite reverse;
        opacity: 0.1;
      }
      .sf-1 {
        top: 18%;
        left: 15%;
        font-size: 10vmin;
        animation-delay: 0s;
        transform: rotate(-15deg);
      }
      .sf-2 {
        bottom: 15%;
        right: 15%;
        font-size: 8vmin;
        animation-delay: -5s;
        transform: rotate(15deg);
      }

      /* 4. 流散星符 (Scattered Dust) */
      .sym-dust {
        opacity: 0.6;
        animation: symbol-twinkle 6s ease-in-out infinite;
      }
      .sd-1 {
        top: 20%;
        right: 25%;
        font-size: 3vmin;
        animation-delay: 1s;
      } /* ★ */
      .sd-2 {
        top: 80%;
        left: 15%;
        font-size: 2.5vmin;
        animation-delay: 2.5s;
      } /* ☆ */
      .sd-3 {
        bottom: 25%;
        right: 35%;
        font-size: 4vmin;
        animation-delay: 0.5s;
        color: var(--witch-cyan);
      } /* ✦ */
      .sd-4 {
        top: 35%;
        left: 10%;
        font-size: 3vmin;
        animation-delay: 3s;
      } /* ✧ */
      .sd-5 {
        top: 10%;
        left: 50%;
        font-size: 2vmin;
        animation-delay: 4s;
      } /* ⚝ */
      .sd-6 {
        bottom: 10%;
        right: 50%;
        font-size: 2vmin;
        animation-delay: 1.5s;
      } /* ✦ */

      /* 巨型悬臂（保留风格，显著降载） */
      .galaxy-arm {
        position: absolute;
        width: 120vmax;
        height: 120vmax;
        filter: blur(var(--blur-strength));
        mix-blend-mode: screen;
        opacity: calc(0.18 * var(--fx-opacity));
        pointer-events: none;
        z-index: -1;
        will-change: transform;
      }
      .arm-primary {
        top: -60vmax;
        left: -60vmax;
        transform-origin: 50% 50%;
        background: conic-gradient(
          from 0deg at 50% 50%,
          transparent 0deg,
          transparent 150deg,
          rgba(74, 20, 140, 0.22) 190deg,
          rgba(168, 192, 255, 0.08) 225deg,
          transparent 265deg,
          transparent 360deg
        );
        animation: mech-spin 220s linear infinite;
      }
      .arm-secondary {
        top: -18vmax;
        left: -18vmax;
        transform-origin: 50% 50%;
        background: conic-gradient(
          from 180deg at 50% 50%,
          transparent 0deg,
          transparent 130deg,
          rgba(0, 229, 255, 0.12) 168deg,
          rgba(168, 192, 255, 0.04) 208deg,
          transparent 246deg,
          transparent 360deg
        );
        animation: mech-spin 170s linear infinite reverse;
      }

      /* 混沌流体（降压版） */
      .chaos-blob {
        position: absolute;
        opacity: calc(0.2 * var(--fx-opacity));
        filter: blur(34px);
        mix-blend-mode: hard-light;
        border-radius: 40% 60% 70% 30% / 40% 50% 60% 50%;
        z-index: -2;
        will-change: transform;
      }
      .blob-purple {
        top: -8%;
        left: -8%;
        width: 56vmin;
        height: 56vmin;
        background: radial-gradient(circle, var(--witch-purple), transparent);
        animation: blob-float 48s ease-in-out infinite alternate;
      }
      .blob-green {
        bottom: -8%;
        right: -8%;
        width: 56vmin;
        height: 56vmin;
        background: radial-gradient(circle, var(--toxic-chartreuse), transparent);
        animation: blob-float 60s ease-in-out infinite alternate-reverse;
      }
      .blob-blue {
        top: 42%;
        left: 42%;
        width: 42vmin;
        height: 42vmin;
        background: radial-gradient(circle, var(--witch-cyan), transparent);
        animation: blob-float 72s ease-in-out infinite alternate;
      }

      /* 四维星空（从 4 层降到 2 层） */
      .star-layer {
        position: absolute;
        inset: -35%;
        width: 170%;
        height: 170%;
        background-image: url('[https://www.transparenttextures.com/patterns/stardust.png](https://www.transparenttextures.com/patterns/stardust.png)');
        background-repeat: repeat;
        mix-blend-mode: screen;
        pointer-events: none;
        z-index: -1;
        will-change: transform;
      }
      .stars-1 {
        transform-origin: 45% 50%;
        background-size: calc(420px * var(--star-scale));
        opacity: calc(0.46 * var(--fx-opacity));
        animation: star-spin 300s linear infinite;
      }
      .stars-2 {
        transform-origin: 62% 58%;
        background-size: calc(760px * var(--star-scale));
        opacity: calc(0.28 * var(--fx-opacity));
        animation: star-spin 420s linear infinite reverse;
      }
      .stars-3,
      .stars-4 {
        display: none;
      }

      /* === 大门 === */
      .gate-doors-container {
        position: absolute;
        inset: 0;
        z-index: 5;
        display: flex;
        justify-content: center;
        pointer-events: none;
      }
      .gate-door {
        position: relative;
        width: 50%;
        height: 100%;
        background: linear-gradient(to bottom, rgba(5, 8, 28, 0.95), rgba(2, 4, 10, 0.98));
        border-right: 1px solid rgba(255, 255, 255, 0.05);
        transition:
          transform 3.5s cubic-bezier(0.4, 0, 0.2, 1),
          opacity 3s ease;
        transform-style: preserve-3d;
        backdrop-filter: none;
      }
      .door-left {
        transform-origin: left center;
        border-right: 2px solid var(--gate-border);
      }
      .door-right {
        transform-origin: right center;
        border-left: 2px solid var(--gate-border);
      }
      .gate-door::before {
        content: '';
        position: absolute;
        inset: 0;
        background-image:
          linear-gradient(
            45deg,
            rgba(255, 255, 255, 0.02) 25%,
            transparent 25%,
            transparent 75%,
            rgba(255, 255, 255, 0.02) 75%,
            rgba(255, 255, 255, 0.02)
          ),
          linear-gradient(
            45deg,
            rgba(255, 255, 255, 0.02) 25%,
            transparent 25%,
            transparent 75%,
            rgba(255, 255, 255, 0.02) 75%,
            rgba(255, 255, 255, 0.02)
          );
        background-size: 60px 60px;
        opacity: 0.5;
      }
      .gate-seam-light {
        position: absolute;
        top: 0;
        left: 50%;
        width: 4px;
        height: 100%;
        background: var(--gate-glow);
        transform: translateX(-50%);
        box-shadow:
          0 0 20px var(--gate-glow),
          0 0 60px var(--gate-glow);
        z-index: 6;
        opacity: 0.7;
        transition: all 0.5s;
      }
      .gate-light-burst {
        position: absolute;
        top: 50%;
        left: 50%;
        width: 100px;
        height: 120vh;
        background: linear-gradient(to right, transparent, rgba(200, 240, 255, 0.9), transparent);
        transform: translate(-50%, -50%) scaleX(0);
        filter: blur(30px);
        opacity: 0;
        z-index: 4;
        pointer-events: none;
      }
      .gate-root.open .door-left {
        transform: rotateY(-100deg) scale(0.9);
        opacity: 0;
      }
      .gate-root.open .door-right {
        transform: rotateY(100deg) scale(0.9);
        opacity: 0;
      }
      .gate-root.open .gate-seam-light {
        opacity: 0;
        width: 0;
      }
      .gate-root.open .gate-light-burst {
        animation: burst-flash 3s ease-out forwards;
      }

      /* === 银钥 === */
      #intro-stage {
        position: absolute;
        top: 0;
        left: 0;
        width: 100%;
        height: 100%;
        z-index: 10;
        transition: all 0.8s ease;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
      }
      .silver-key-btn {
        position: relative;
        width: 130px;
        height: 130px;
        display: flex;
        align-items: center;
        justify-content: center;
        cursor: pointer;
        transition: all 0.5s cubic-bezier(0.34, 1.56, 0.64, 1);
      }
      .key-icon {
        font-size: 85px;
        filter: grayscale(100%) brightness(150%) drop-shadow(0 5px 5px rgba(0, 0, 0, 0.5));
        transition: all 0.5s ease;
        user-select: none;
      }
      .key-halo {
        position: absolute;
        width: 100%;
        height: 100%;
        border: 1px solid rgba(200, 230, 255, 0.2);
        border-radius: 50%;
        animation: mech-spin 30s linear infinite;
        opacity: 0.3;
        transition: all 0.5s ease;
        box-shadow: 0 0 10px rgba(0, 0, 0, 0.5);
      }
      .key-halo::after {
        content: '';
        position: absolute;
        inset: -10px;
        border: 1px dashed rgba(200, 230, 255, 0.15);
        border-radius: 50%;
        animation: mech-spin 20s linear infinite reverse;
      }
      .silver-key-btn:hover .key-icon {
        transform: scale(1.1) rotate(-10deg);
        filter: grayscale(0%) brightness(200%) drop-shadow(0 0 25px var(--witch-cyan));
      }
      .silver-key-btn:hover .key-halo {
        border-color: var(--witch-purple);
        opacity: 1;
        transform: scale(1.1);
        box-shadow: 0 0 20px rgba(123, 31, 162, 0.5);
      }
      .unlocking .key-icon {
        animation: key-unlock 1s cubic-bezier(0.6, -0.28, 0.735, 0.045) forwards;
      }
      .unlocking .key-halo {
        animation: halo-expand 1.2s ease-out forwards;
      }
      .intro-fadeout {
        opacity: 0;
        transform: scale(1.5);
        pointer-events: none;
      }

      /* === 奖励容器 (300px 宽度适配) === */
      .reward-container {
        display: none;
        display: flex;
        flex-wrap: wrap;
        justify-content: center;
        gap: 30px;
        width: 100%;
        padding: 40px 20px;
        box-sizing: border-box;
        z-index: 5;
        margin-top: 5vh;
      }

      .skill-orb {
        flex: 0 1 300px;
        max-width: 300px;
        min-width: 260px;
        height: 420px;

        background: rgba(10, 15, 30, 0.75);
        border: 1px solid rgba(255, 255, 255, 0.1);
        border-radius: 12px;
        position: relative;
        overflow: hidden;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: flex-start;
        padding: 15px;
        cursor: pointer;
        transition:
          transform 0.22s cubic-bezier(0.25, 0.8, 0.25, 1),
          background 0.22s ease,
          border-color 0.22s ease,
          box-shadow 0.22s ease;
        box-shadow: 0 5px 20px rgba(0, 0, 0, 0.5);
        backdrop-filter: none;
        opacity: 0;
      }
      .skill-orb:hover {
        transform: translateY(-10px) scale(1.05) !important;
        z-index: 20;
        background: rgba(16, 20, 35, 0.9);
        border-color: var(--witch-cyan);
      }
      .skill-orb::after {
        content: '';
        position: absolute;
        top: 0;
        left: -100%;
        width: 50%;
        height: 100%;
        background: linear-gradient(to right, transparent, rgba(255, 255, 255, 0.2), transparent);
        transform: skewX(-25deg);
        pointer-events: none;
        z-index: 10;
      }
      .orb-rare:hover::after,
      .orb-epic:hover::after,
      .orb-legend:hover::after,
      .orb-mythic:hover::after,
      .orb-excellent:hover::after {
        animation: sheen-pass 0.75s ease-in-out forwards;
      }

      /* 品质皮肤 */
      .orb-common {
        border-color: var(--q-common);
        box-shadow: 0 0 10px rgba(176, 196, 222, 0.2);
      }
      .orb-common:hover {
        box-shadow: 0 0 20px var(--q-common);
      }
      .orb-excellent {
        border-color: var(--q-excellent);
        box-shadow: 0 0 10px rgba(0, 230, 118, 0.3);
      }
      .orb-excellent:hover {
        box-shadow:
          0 0 25px var(--q-excellent),
          inset 0 0 20px rgba(0, 230, 118, 0.1);
      }
      .orb-rare {
        border-color: var(--q-rare);
        box-shadow: 0 0 10px rgba(0, 188, 212, 0.3);
      }
      .orb-rare:hover {
        box-shadow:
          0 0 25px var(--q-rare),
          inset 0 0 20px rgba(0, 188, 212, 0.1);
      }
      .orb-epic {
        border-color: var(--q-epic);
        box-shadow: 0 0 15px rgba(156, 39, 176, 0.4);
      }
      .orb-epic:hover {
        box-shadow:
          0 0 35px var(--q-epic),
          inset 0 0 30px rgba(156, 39, 176, 0.2);
        animation: none;
      }
      .orb-legend {
        border-color: var(--q-legend);
        box-shadow: 0 0 20px rgba(255, 215, 0, 0.5);
        background: linear-gradient(145deg, rgba(255, 215, 0, 0.1), rgba(10, 15, 30, 0.9));
      }
      .orb-legend:hover {
        box-shadow:
          0 0 40px var(--q-legend),
          inset 0 0 40px rgba(255, 215, 0, 0.2);
        animation: none;
      }
      .orb-mythic {
        border-color: var(--q-mythic);
        box-shadow: 0 0 25px rgba(255, 82, 82, 0.6);
        background: linear-gradient(145deg, rgba(255, 0, 0, 0.15), #000);
      }
      .orb-mythic:hover {
        box-shadow:
          0 0 50px var(--q-mythic),
          inset 0 0 50px rgba(255, 0, 0, 0.3);
        animation: none;
      }
      .orb-other {
        border-color: var(--q-other);
        box-shadow: 0 0 15px rgba(120, 144, 156, 0.3);
        border-style: dashed;
      }

      .orb-icon {
        font-size: 50px;
