    <script>
      const rawXml = `<root>$1</root>`;
      const skills = [];

      try {
        const parser = new DOMParser();
        const doc = parser.parseFromString(rawXml, 'text/xml');
        const items = doc.getElementsByTagName('skill');
        for (let i = 0; i < items.length; i++) {
          skills.push({
            name: items[i].getElementsByTagName('name')[0]?.textContent || '未知',
            type: items[i].getElementsByTagName('type')[0]?.textContent || '其它',
            quality: items[i].getElementsByTagName('quality')[0]?.textContent || '其它',
            cost: items[i].getElementsByTagName('cost')[0]?.textContent || '无消耗',
            tags: items[i].getElementsByTagName('tags')[0]?.textContent || '',
            effect: items[i].getElementsByTagName('effect')[0]?.textContent || '效果解析中...',
            desc: items[i].getElementsByTagName('desc')[0]?.textContent || '暂无描述',
            comment: items[i].getElementsByTagName('comment')[0]?.textContent || '...',
          });
        }
      } catch (e) {}

      const keyBtn = document.getElementById('silver-key-btn');
      const intro = document.getElementById('intro-stage');
      const container = document.getElementById('reward-container');
      const gateRoot = document.getElementById('gate-root');
      const modal = document.getElementById('modal-backdrop');
      const modalCard = document.getElementById('modal-card');

      const cpuCores = navigator.hardwareConcurrency || 0;
      const lowCpu = cpuCores === 0 || cpuCores <= 8;
      const heavyData = skills.length > 12;
      const perfLite = lowCpu || heavyData;
      if (perfLite) gateRoot.classList.add('perf-lite');

      function getQualityClass(q) {
        if (q.includes('优良')) return 'orb-excellent';
        if (q.includes('稀有')) return 'orb-rare';
        if (q.includes('史诗')) return 'orb-epic';
        if (q.includes('传说')) return 'orb-legend';
        if (q.includes('神话') || q.includes('唯一')) return 'orb-mythic';
        if (q.includes('普通')) return 'orb-common';
        return 'orb-other';
      }

      keyBtn.addEventListener('click', () => {
        keyBtn.classList.add('unlocking');
        intro.classList.add('intro-fadeout');

        setTimeout(() => {
          intro.style.display = 'none';
          gateRoot.classList.add('open');

          setTimeout(
            () => {
              container.style.display = 'flex';
              render();
            },
            perfLite ? 320 : 1200,
          );
        }, 600);
      });

      function render() {
        let i = 0;
        const batchSize = perfLite ? 5 : 10;

        const appendBatch = () => {
          const frag = document.createDocumentFragment();
          const end = Math.min(i + batchSize, skills.length);

          for (; i < end; i++) {
            const s = skills[i];
            const orb = document.createElement('div');
            const qClass = getQualityClass(s.quality);
            orb.className = `skill-orb ${qClass}`;

            if (perfLite) {
              orb.style.opacity = '1';
              orb.style.animation = 'none';
            } else {
              orb.style.animation = `cosmic-birth 1.1s cubic-bezier(0.19, 1, 0.22, 1) forwards ${Math.min(i * 0.15, 1.2)}s`;
            }

            let tagsHtml = '';
            const tagMatches = s.tags.match(/\[(.*?)\]/g);
            if (tagMatches) {
              tagsHtml = tagMatches.map(t => `<span class="tag-pill">${t.replace(/[\[\]]/g, '')}</span>`).join('');
            } else {
              tagsHtml = `<span class="tag-pill">${s.tags}</span>`;
            }

            const nameClass = s.name.length > 8 ? 'value scroll' : 'value';

            orb.innerHTML = `
                <div class="orb-icon">🔮</div>
                <div class="info-layout">
                    <div class="info-box box-name">
                        <span class="label">NAME</span>
                        <div class="value-container">
                            <span class="${nameClass}">${s.name}</span>
                        </div>
                    </div>
                    <div class="info-box box-type">
                        <span class="label">TYPE</span>
                        <span class="value">${s.type}</span>
                    </div>
                    <div class="info-box box-cost">
                        <span class="label">COST</span>
                        <span class="value">${s.cost}</span>
                    </div>
                    <div class="info-box box-tags">
                        <span class="label">TAGS</span>
                        <div style="display:flex; flex-wrap:wrap; justify-content:center; gap:4px;">${tagsHtml}</div>
                    </div>
                </div>
                <div class="click-hint">[ ${s.quality} ] · CLICK FOR INFO</div>
            `;
            orb.onclick = () => openModal(s, qClass);
            frag.appendChild(orb);
          }

          container.appendChild(frag);
          if (i < skills.length) requestAnimationFrame(appendBatch);
        };

        requestAnimationFrame(appendBatch);
      }

      function openModal(s, qClass) {
        document.getElementById('m-title').textContent = s.name;
        document.getElementById('m-sub').textContent = `— ${s.quality} · ${s.type} —`;

        let color = '#78909c';
        if (qClass.includes('common')) color = '#b0c4de';
        if (qClass.includes('excellent')) color = '#00e676';
        if (qClass.includes('rare')) color = '#00bcd4';
        if (qClass.includes('epic')) color = '#9c27b0';
        if (qClass.includes('legend')) color = '#ffd700';
        if (qClass.includes('mythic')) color = '#ff5252';

        modalCard.style.borderColor = color;
        modalCard.style.boxShadow = `0 0 30px ${color}40`;

        document.getElementById('m-effect').innerHTML = s.effect.replace(/\n/g, '<br>');
        document.getElementById('m-desc').innerHTML = s.desc.replace(/\n/g, '<br>');
        document.getElementById('m-comment').innerHTML = `<strong>阿比盖尔:</strong> "${s.comment}"`;
        modal.style.display = 'flex';
      }

      document.getElementById('modal-close').onclick = () => (modal.style.display = 'none');
      modal.onclick = e => {
        if (e.target === modal) modal.style.display = 'none';
      };
    </script>
